import{_ as o,o as t,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"98. Royal Commission Working Group","description":"","frontmatter":{"title":"98. Royal Commission Working Group","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["discipline","governance"]},"headers":[],"relativePath":"ebas/mspp/clinical-supervision/98-royal-commission-working-group.md","filePath":"ebas/mspp/clinical-supervision/98-royal-commission-working-group.md"}'),s={name:"ebas/mspp/clinical-supervision/98-royal-commission-working-group.md"};function r(a,e,p,m,l,c){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_98-royal-commission-working-group" tabindex="-1">98. Royal Commission Working Group <a class="header-anchor" href="#_98-royal-commission-working-group" aria-label="Permalink to &quot;98. Royal Commission Working Group&quot;">​</a></h1><p><strong>a.</strong> The VHIA and HSU (the Parties) acknowledge that the implementing the outcomes of the Reports (including its Interim Report) of the Royal Commission into Victoria’s Mental Health System (Royal Commission) may require changes to this Agreement as it applies to the employment of Psychologists and/or any other disciplines, for example, Pharmacists and Dietitians.</p><p><strong>b.</strong> This clause provides a framework for ensuring the Parties are able to properly consider any industrial implications arising from the Royal Commission Reports , and any provisions of this Agreement that may require amendment in order to accommodate the implementation of any Report arising from the Royal Commission.</p><p><strong>98.2</strong> Consultation Process Nothing in this Agreement impacts upon or derogates from any Government or Department of Health initiated consultation process with the HSU and other stakeholders regarding the implementation of the Royal Commission Reports, including legislative changes. Such consultation processes may occur prior to, or concurrently with the functions of the Working Group.</p><p><strong>98.3</strong> Working Group Structure</p><p><strong>a.</strong> The parties agree to establish a Royal Commission Working Group (RCWG) as soon as practicable but in any case no later than 1 month after the commencement of the Agreement.</p><p><strong>b.</strong> The working Committee will consist of representatives from:</p><p><strong>(i)</strong> HSU</p><p><strong>(ii)</strong> Department of Health</p><p><strong>(iii)</strong> VHIA</p><p><strong>(iv)</strong> Others as invited by the Committee</p><p><strong>c.</strong> The RCWG will be chaired by an independent third party agreed by the parties, or where agreement cannot be reached, by a person nominated by the Minister of Mental Health.</p><p><strong>d.</strong> The RCWG will meet every two months or as required in order to complete its objectives.</p><p><strong>98.4</strong> Working Group Objectives The Working Group will be responsible for delivering the following outcomes:</p><p><strong>a.</strong> identifying those recommendations and proposals of the Royal Commission which have implications for the operation of the Agreement.</p><p><strong>b.</strong> Identifying any amendments to the Agreement necessary to give effect to the Royal Commission recommendations and proposals and the implementation of those recommendations and proposals.</p><p><strong>c.</strong> Seek to reach consensus on any necessary amendments to the Agreement.</p><p><strong>d.</strong> Seek to address and resolve any significant industrial issues associated with the implementation of the Royal Commission recommendations and proposals and the process of legislative changes.</p><p><strong>e.</strong> Considering and responding to any specific requests from the Department of Health.</p><p><strong>98.5</strong> Implementation In addition to the Objectives listed at 98.4 the RCWG will consider how it could assist in supporting the implementation of the Royal Commission recommendations.</p><p><strong>98.6</strong> Variation of Agreement For the avoidance of doubt, the collaboration contained within this clause would occur prior to, and does not replace or imply support for, any formal process for varying the agreement under Part 2–4 of the Act.</p><p>Executed as an agreement</p><p>Executed by the Victoria,, Hospitals&#39; Industrial Association by its duly appointed officer on behalf of Ille Employers IISled In <a href="/eba/ebas/mspp/schedules/1-employer-parties.html">Schedule 1</a>:</p><p>,~ i~tlfil. Chief Executive Officer</p><p>88 Maribyrnong SI FooCscray VIC 3011</p><p>2 if Oc10&#39;3dl.- 2D~ &quot;Z---</p><p>In the presence of:</p><p>Witness {signature)</p><p>Name of witness (print)</p><p>Executed by the Health Services Union by its duly appointed officer:</p><p>………………………………… Matt Hammond Secretary Health Services Union Victoria No 4 Branch</p><p>Level 1/62 Lygon Street Carlton VIC 3053</p><p>Date: 28 October 2022</p><p>In the presence of:</p><p>………………………………….. Witness (signature)</p><p>Paul Elliott ………………………………….. Name of witness (print)</p><p>Executed by the Health Services Union by its duly appointed officer:</p><p>………………………………… Paul Healey Secretary Health Services Union Victoria No 2 Branch 7 Grattan Street Carlton VIC 3053</p><p>Date: 2 November 2022</p><p>In the presence of:</p><p>………………………………….. Witness (signature)</p><p>Kate Marshall ………………………………….. Name of witness (print)</p><p>Plain language terms: royal commission.</p>',43)])])}const d=o(s,[["render",r]]);export{g as __pageData,d as default};
